#include <bits/stdc++.h>
using namespace std;
int n,a[105];
int main(){
	cin >> n;
	for (int i = n;i >= 0;i--) cin >> a[i];
	for (int i = n;i >= 0;i--){
		if (a[i] > 1 && i != n) cout << "+";
		if (a[i] == -1 && i != 0) cout << "-";
		if (a[i] != 1 && a[i] != -1 && a[i] != 0 || i == 0) cout << a[i];
		if (a[i] != 0 && i != 0){
			cout << "x";
			if (i != 0 && i != 1) cout << "^" << i;
		}
	}
	return 0;
}
